<script setup>
import {computed, onMounted, ref, watch} from 'vue'
import axios from 'axios'
import debounce from 'lodash/debounce';
import {useDate} from 'vuetify';
import {useForm, Link} from "@inertiajs/vue3";
import {route} from "ziggy-js";

const date = useDate()

const uris = ref([])
const search = ref('')
const loading = ref(false)

const headerUris = [
    { title: 'Address', key: 'address' },
    { title: 'Units', key: 'units' },
    { title: 'Valid', key: 'is_valid' },
    { title: 'Follow', key: 'follow' },
    { title: 'Created', key: 'created_at' },
]

const fetchUris = async () => {
    loading.value = true

    const { data } = await axios.get(route('uris.index'), {
        params: {
            search: search.value,
        }
    })

    uris.value = data
    loading.value = false
}

// 🔹 загрузка при старте
fetchUris()

// 🔹 следим за изменением search
watch(search, (newVal) => {
    fetchUris(newVal);
});


const filteredUris = computed(()=>{
    if (!search.value) return uris.value

    const term = search.value.toLowerCase()

    return uris.value.filter(uri => {
        const addressMatch = uri.address?.toLowerCase().includes(term)

        const unitMatch = uri.units?.some(unit =>
            unit.name?.toLowerCase().includes(term)
        )

        return addressMatch || unitMatch;
    })
})
const formUri = useForm({
    address: null,
})
function storeUri(){
    formUri.post(route('web.uri.store'), {
        replace: false,
        preserveState: true,
        preserveScroll: false,
        onSuccess: ()=> {
            formUri.reset();
            fetchUris()
        },
    });
}

</script>

<template>
    <v-container fluid>
        <v-row>
            <v-col cols="3">
                <v-text-field
                    v-model="search"
                    label="Поиск uris"
                    variant="solo-filled"
                    color="rose"
                    density="comfortable"
                    hide-details
                    clearable
                />
            </v-col>
        </v-row>
        <v-row>
            <v-col>
                <v-data-table
                    :headers="headerUris"
                    :items="uris"
                    items-per-page="1000"
                    fixed-header
                    height="888px"
                    density="compact"
                    class="text-xs border rounded border-red-50"
                    hover
                >
                    <template v-slot:item.address="{item}">
                        <a :href="item.address" target="_blank"
                           class="text-xs text-green-400 inline-block"
                        >{{item.address}}</a>
                    </template>
                    <template v-slot:item.units="{item}">
                        <div v-for="unit in item.units">
                            <Link :href="route('web.unit.show', unit.id)">{{unit.name}}</Link>
                        </div>
                    </template>
                    <template v-slot:item.created_at="{item}">
                        <span class="text-xs font-sans">{{date.format(item.created_at, 'fullDate')}}</span>
                    </template>
                </v-data-table>
            </v-col>
        </v-row>
    </v-container>
</template>

